arguments.command:
cat > /tmp/draw_t2i_payload.json << 'JSONEOF'
{
  "model": "wan2.6-image",
  "input": {
    "messages": [
      {
        "role": "user",
        "content": [
          {
            "text": "A beautiful anime-style goddess with short hair, emotionless deadpan expression (三无气质 - silent, expressionless, mysterious), slightly seductive cold beauty, dressed as a literary girl (文学少女) - soft cream-colored cardigan, pleated skirt, holding an old book, standing in a dreamy library with warm amber light streaming through windows. Rei Ayanami vibe. Elegant, cool, captivating."
          }
        ]
      }
    ]
  },
  "parameters": {
    "enable_interleave": false,
    "negative_prompt": "ugly, deformed, blurry, low quality, distorted, bad anatomy, watermark, text, signature, extra limbs, fused fingers, too many fingers, long neck",
    "n": 1,
    "size": "1024*1024",
    "watermark": false,
    "prompt_extend": true
  }
}
JSONEOF

echo "Sending API request..."
HTTP_CODE=$(curl -s -o /tmp/draw_response_t2i.json -w "%{http_code}" \
  -X POST "https://dashscope.aliyuncs.com/api/v1/services/aigc/multimodal-generation/generation" \
  -H "Authorization: Bearer $DASHSCOPE_API_KEY" \
  -H "Content-Type: application/json" \
  -d @/tmp/draw_t2i_payload.json)

echo "HTTP status: $HTTP_CODE"

